import{_ as a,a as e,b as d,c as i,d as p,e as n}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as s,o as r,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"IP 定位与用户管理","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Other/ip-geolocation-and-user-management.md","filePath":"cn/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),h={name:"cn/Other/ip-geolocation-and-user-management.md"};function c(b,t,P,I,m,u){return r(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="ip-定位与用户管理" tabindex="-1">IP 定位与用户管理 <a class="header-anchor" href="#ip-定位与用户管理" aria-label="Permalink to &quot;IP 定位与用户管理&quot;">​</a></h1><p>IP 定位用来把上传者、登录设备等记录里的 IP 显示成大概的地理位置。</p><p>开启后，后台可以更直观看到访问来源、上传来源，也可以在用户管理里对异常 IP 单独禁止或恢复上传。</p><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><p>IP 定位在：</p><p>系统配置 -&gt; 其他设置 -&gt; IP 定位</p><p><img src="'+a+`" alt="IP定位" loading="lazy"></p><h2 id="可以配置什么" tabindex="-1">可以配置什么 <a class="header-anchor" href="#可以配置什么" aria-label="Permalink to &quot;可以配置什么&quot;">​</a></h2><p>新版 IP 定位支持多个来源，不再只依赖单一地图服务。</p><table tabindex="0"><thead><tr><th>配置项</th><th>作用</th></tr></thead><tbody><tr><td>IP 解析语言</td><td>选择地址显示语言，例如 English、简体中文、日本语、Français 等。</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind 账号 ID，用于 MaxMind GeoLite Web Service。</td></tr><tr><td>MaxMind License Key</td><td>MaxMind 的 License Key。</td></tr><tr><td>腾讯地图 Key</td><td>腾讯位置服务 Key，适合中文地址和国内 IP。</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi Key，支持多语言 IP 地址解析。</td></tr></tbody></table><p>这些配置可以按需填写，不需要每一项都填。</p><p>如果你什么 Key 都不填，系统也会尝试使用内置免费来源解析 IP，只是稳定性、语言支持和精度可能不如自己配置的服务。</p><h2 id="推荐怎么选" tabindex="-1">推荐怎么选 <a class="header-anchor" href="#推荐怎么选" aria-label="Permalink to &quot;推荐怎么选&quot;">​</a></h2><p>如果你主要看中文地址：</p><ol><li>IP 解析语言选择“简体中文”。</li><li>配置腾讯地图 Key。</li><li>有条件的话再配置 MaxMind 或 ipapi 作为补充。</li></ol><p>如果你主要看英文或多语言地址：</p><ol><li>IP 解析语言选择需要的语言。</li><li>配置 MaxMind Account ID 和 License Key。</li><li>需要更好的多语言结果时，再配置 ipapi Key。</li></ol><h2 id="maxmind-怎么配置" tabindex="-1">MaxMind 怎么配置 <a class="header-anchor" href="#maxmind-怎么配置" aria-label="Permalink to &quot;MaxMind 怎么配置&quot;">​</a></h2><p>MaxMind 需要填写两项：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>在 MaxMind 后台可以看到账号 ID，并在 License Keys 页面生成 License Key。</p><p><img src="`+e+'" alt="MaxMind Key配置" loading="lazy"></p><p>生成后，把 Account ID 和 License Key 分别填回图床后台保存即可。</p><p>MaxMind 免费计划适合日常使用，但有调用次数限制。如果超过额度，系统会继续尝试其他可用来源。</p><h2 id="ipapi-怎么配置" tabindex="-1">ipapi 怎么配置 <a class="header-anchor" href="#ipapi-怎么配置" aria-label="Permalink to &quot;ipapi 怎么配置&quot;">​</a></h2><p>ipapi 使用 APILayer 的 API Key。</p><p>进入 ipapi 控制台后，复制页面上的 API Key。</p><p><img src="'+d+'" alt="ipapi配置" loading="lazy"></p><p>然后填入图床后台的“ipapi Key”并保存。</p><p>ipapi 支持多语言 IP 地址解析，适合想让后台地址按指定语言显示的场景。免费计划也有调用次数限制，额度用完后系统会继续尝试其他可用来源。</p><h2 id="腾讯地图-key-怎么配置" tabindex="-1">腾讯地图 Key 怎么配置 <a class="header-anchor" href="#腾讯地图-key-怎么配置" aria-label="Permalink to &quot;腾讯地图 Key 怎么配置&quot;">​</a></h2><p>腾讯地图 Key 适合中文地址，尤其是国内 IP。</p><p>在腾讯位置服务控制台创建 Key 时，建议启用：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>创建完成后，把 Key 填到“腾讯地图 Key”里保存。</p><p>如果你只想简单使用中文 IP 定位，填腾讯地图 Key 就可以先用起来。</p><h2 id="用户管理里看什么" tabindex="-1">用户管理里看什么 <a class="header-anchor" href="#用户管理里看什么" aria-label="Permalink to &quot;用户管理里看什么&quot;">​</a></h2><p>入口在后台顶部的用户管理。</p><p><img src="'+i+'" alt="用户管理显示" loading="lazy"></p><p>用户管理主要看每个 IP 的上传情况：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>IP 来源</td><td>上传者的来源 IP。</td></tr><tr><td>地址</td><td>IP 定位解析出来的大概位置。</td></tr><tr><td>上传总量</td><td>这个 IP 上传文件占用的总大小。</td></tr><tr><td>上传次数</td><td>这个 IP 上传过多少次。</td></tr><tr><td>允许上传</td><td>打开就是允许上传，关闭就是禁止上传。</td></tr></tbody></table><p>点击左侧展开箭头，可以查看这个 IP 上传过的文件列表。</p><p>文件列表里可以看到文件名、文件预览、文件大小、审查结果、文件状态和上传时间。遇到异常上传时，可以先展开看具体文件，再决定是否禁止这个 IP 继续上传。</p><p>如果发现某个 IP 上传异常，可以直接把“允许上传”关掉。后面这个 IP 再上传时，就会被拦截。</p><h2 id="搜索、排序和高级筛选" tabindex="-1">搜索、排序和高级筛选 <a class="header-anchor" href="#搜索、排序和高级筛选" aria-label="Permalink to &quot;搜索、排序和高级筛选&quot;">​</a></h2><p>用户管理顶部可以直接搜索 IP 来源或地址。</p><p>排序可以按时间、上传次数、上传总量切换，方便先看最近上传、上传次数最多，或者占用空间最大的 IP。</p><p>需要更精确排查时，可以打开高级筛选。</p><p><img src="'+p+'" alt="用户管理高级筛选" loading="lazy"></p><p>高级筛选支持这些条件：</p><table tabindex="0"><thead><tr><th>筛选项</th><th>用法</th></tr></thead><tbody><tr><td>时间范围</td><td>只看某一段时间内上传过文件的 IP。</td></tr><tr><td>访问状态</td><td>按正常、屏蔽等状态筛选。</td></tr><tr><td>黑白名单</td><td>按白名单、黑名单、未设置筛选。</td></tr><tr><td>文件类型</td><td>只看上传过图片、视频、音频、文档、代码或其他类型文件的 IP。</td></tr><tr><td>文件大小</td><td>按上传文件大小范围筛选。</td></tr><tr><td>年龄分级</td><td>按未设置、全年龄、R12+、R16+、R18 等分级筛选。</td></tr><tr><td>文件状态</td><td>按文件当前状态筛选，方便排查异常文件。</td></tr></tbody></table><p>筛选完点“应用筛选”即可生效，需要恢复全部数据时点“重置”。</p><h2 id="手机端显示" tabindex="-1">手机端显示 <a class="header-anchor" href="#手机端显示" aria-label="Permalink to &quot;手机端显示&quot;">​</a></h2><p>手机端会把用户管理改成卡片显示。</p><p><img src="'+n+`" alt="手机端显示用户管理效果" loading="lazy"></p><p>每张卡片会显示 IP、地址、上传总量、上传次数和允许上传开关。手机上不用横向拖表格，也可以直接操作。</p><h2 id="地址不准怎么办" tabindex="-1">地址不准怎么办 <a class="header-anchor" href="#地址不准怎么办" aria-label="Permalink to &quot;地址不准怎么办&quot;">​</a></h2><p>IP 定位显示的是大概位置，不是精确门牌地址。</p><p>如果用户使用代理、机房、云服务器、跨境网络，显示位置可能和真实位置不一样。</p><p>所以这个功能更适合用来判断大致来源、发现异常上传、辅助封禁，不建议当成精确定位工具。</p><h2 id="常见情况" tabindex="-1">常见情况 <a class="header-anchor" href="#常见情况" aria-label="Permalink to &quot;常见情况&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>说明</th></tr></thead><tbody><tr><td>地址显示为空</td><td>可能还没解析成功，或者当前 IP 来源暂时不可用。</td></tr><tr><td>地址语言不对</td><td>检查“IP 解析语言”，并确认已配置支持该语言的来源。</td></tr><tr><td>地址显示成机房</td><td>很多代理、云服务器、爬虫工具都会显示成机房或运营商地址。</td></tr><tr><td>上传次数很高</td><td>可以重点检查这个 IP，必要时关闭允许上传。</td></tr><tr><td>上传总量很大</td><td>可以排序或筛选后展开查看具体文件，确认是否异常占用空间。</td></tr><tr><td>禁止后又想恢复</td><td>把“允许上传”开关重新打开即可。</td></tr></tbody></table><h2 id="简单流程" tabindex="-1">简单流程 <a class="header-anchor" href="#简单流程" aria-label="Permalink to &quot;简单流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打开其他设置里的 IP 定位</span></span>
<span class="line"><span>-&gt; 选择 IP 解析语言</span></span>
<span class="line"><span>-&gt; 按需要填写 MaxMind、腾讯地图或 ipapi</span></span>
<span class="line"><span>-&gt; 保存设置</span></span>
<span class="line"><span>-&gt; 打开用户管理查看 IP 来源、地址、上传总量和上传次数</span></span>
<span class="line"><span>-&gt; 用搜索、排序或高级筛选排查异常 IP</span></span>
<span class="line"><span>-&gt; 按需要允许或禁止上传</span></span></code></pre></div>`,64)])])}const _=s(h,[["render",c]]);export{x as __pageData,_ as default};
